mapper.select:
select r.id, r.reporter_id, r.target_type, r.target_id, r.report_config_id, r.reason, r.image_urls, r.audit_status, r.audit_user_id, r.audit_time, r.created_at, IFNULL(m.idno, '') AS reporter_idno, IFNULL(m.nickname, '') AS reporter_nickname, IFNULL(c.report_type, '') AS report_type_name, IFNULL(pm.id, '') AS publisher_user_id, IFNULL(pm.idno, '') AS publisher_idno, IFNULL(pm.nickname, '') AS publisher_nickname, CASE WHEN r.target_type = 'square' THEN sp.id WHEN r.target_type = 'moment' THEN mo.id ELSE null END AS post_id, CASE WHEN r.target_type = 'square' THEN sp.odic_stake_status ELSE null END AS post_status, CASE WHEN r.target_type = 'square' THEN sp.status WHEN r.target_type = 'moment' THEN mo.status ELSE null END AS post_visible_status, CASE WHEN r.target_type = 'square' THEN sp.content WHEN r.target_type = 'moment' THEN mo.content ELSE null END AS post_content, CASE WHEN r.target_type = 'square' THEN sp.image_urls WHEN r.target_type = 'moment' THEN mo.image_urls ELSE null END AS post_image_urls, CASE WHEN r.target_type = 'square' THEN sp.video ELSE null END AS post_video from t_piamom_report_record r left join t_member m on m.id = r.reporter_id left join t_piamom_report_config c on c.id = r.report_config_id left join t_piamom_square_post sp on r.target_type = 'square' and sp.id = r.target_id left join t_piamom_moment mo on r.target_type = 'moment' and mo.id = r.target_id left join t_member pm on pm.id = case when r.target_type = 'square' then sp.user_id when r.target_type = 'moment' then mo.user_id else null end
order by ${orderBy} order by r.created_at desc
limit #{pageNo}, #{pageSize}

mapper.update:
update t_piamom_report_record
set audit_status = #{auditStatus}, audit_user_id = #{auditUserId}, audit_time = #{auditTime}
where id = #{id}
  and audit_status = 0
